import requests, sys

def get(url):
    r = requests.get(url, timeout=10)
    r.raise_for_status()
    return r.content

def find_jpeg_comments(data):
    i = 0
    comments = []
    if not (data[:2] == b'\xff\xd8'):
        return comments
    i = 2
    while i < len(data):
        if data[i] != 0xFF:
            i += 1
            continue
        # skip fill bytes
        while i < len(data) and data[i] == 0xFF:
            i += 1
        if i >= len(data):
            break
        marker = data[i]
        i += 1
        if marker in (0xD8, 0xD9):
            continue
        if i+1 >= len(data):
            break
        seglen = int.from_bytes(data[i:i+2], 'big')
        i += 2
        segdata = data[i:i+seglen-2]
        if marker == 0xFE:  # COM
            comments.append(segdata)
        i += seglen-2
    return comments

for name in ['dev1.jpeg','dev2.jpeg']:
    data = get('http://localhost:80/' + name)
    print(name, 'size', len(data))
    comms = find_jpeg_comments(data)
    if comms:
        for c in comms:
            try:
                print('COMMENT:', c.decode('utf-8','ignore'))
            except Exception:
                print('COMMENT (bytes):', c[:60])
    else:
        print('No JPEG comments found')
    # Check for embedded ZIP or flag-like strings
    if b'PK\x03\x04' in data:
        print('Embedded ZIP detected at offset', data.index(b'PK\x03\x04'))
    for token in [b'FLAG', b'flag', b'CTF', b'ctf', b'{', b'}']:
        if token in data:
            print('Found token', token)
    print('-'*40)
